mapper.select:
SELECT ISNULL(MAX(TOT_DAY), 20)
FROM HRTANNUALDETAIL01
WHERE COMPANY = #{company}
  AND YYYY = #{yyyy}
  AND EMP_CODE = #{empCode}

mapper.update:
UPDATE HRTANNUALDETAIL01
SET USE_DAY = #{useDay},
    BALANCE_DAY = ISNULL(TOT_DAY, 20) - #{useDay},
    UPDATED_AT = GETDATE()
WHERE COMPANY = #{company}
  AND YYYY = #{yyyy}
  AND EMP_CODE = #{empCode}

mapper.select:
SELECT r.REQ_ID AS requestId, r.REQ_GROUP AS requestCategory, CASE WHEN r.REQ_GROUP = 'OTHER' THEN o.CHANGE_SHIFT_CODE ELSE r.REQ_TYPE END AS requestWorkCode, CONVERT(VARCHAR(10), r.TARGET_DATE, 23) AS workDate, CONVERT(VARCHAR(10), ISNULL(o.END_DATE, r.TARGET_DATE), 23) AS endDate, g.WORK_MIN AS requestWorkMin FROM HRTATTENDANCEREQUEST01 r LEFT JOIN HRTATTENDANCE_GENERAL01 g ON g.COMPANY = r.COMPANY AND g.REQ_ID = r.REQ_ID LEFT JOIN HRTATTENDANCE_OTHER01 o ON o.COMPANY = r.COMPANY AND o.REQ_ID = r.REQ_ID WHERE r.COMPANY = #{company} AND r.TARGET_EMP_CODE = #{empCode} AND ( r.STATUS = 'APPROVED'
OR r.STATUS = 'SUBMITTED'
)
AND r.REQ_ID <> #{excludeRequestId}
AND ( ( r.REQ_GROUP = 'GENERAL' AND r.REQ_TYPE IN ('조퇴', '외출', '전반차', '후반차', '오전반차', '오후반차') AND YEAR(r.TARGET_DATE) = #{yyyy} ) OR ( r.REQ_GROUP = 'OTHER' AND o.CHANGE_SHIFT_CODE = '06' AND o.START_DATE <= DATEFROMPARTS(#{yyyy}, 12, 31) AND o.END_DATE >= DATEFROMPARTS(#{yyyy}, 1, 1) ) )
